mapper.select:
SELECT service_type_id, type_name, description, base_price, min_duration, image_url, create_time, update_time
FROM service_type
WHERE service_type_id = #{serviceTypeId}

mapper.update:
UPDATE service_type
type_name = #{typeName}, description = #{description}, base_price = #{basePrice}, min_duration = #{minDuration}, image_url = #{imageUrl},
WHERE service_type_id = #{serviceTypeId}
